import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import { api }     from '../services/api';
import './CheckoutPage.css';

/* ─── Load Razorpay SDK dynamically ─────────────────────────── */
function loadRazorpayScript() {
  return new Promise(resolve => {
    if (document.getElementById('razorpay-sdk')) { resolve(true); return; }
    const script  = document.createElement('script');
    script.id     = 'razorpay-sdk';
    script.src    = 'https://checkout.razorpay.com/v1/checkout.js';
    script.onload = () => resolve(true);
    script.onerror= () => resolve(false);
    document.body.appendChild(script);
  });
}

export default function CheckoutPage() {
  const { cart, subtotal, clearCart } = useCart();
  const { user, isLoggedIn, token }   = useAuth();
  const navigate                      = useNavigate();

  const [form, setForm] = useState({
    name:    '',
    phone:   '',
    address: ''
  });
  const [loc,           setLoc]           = useState(null);
  const [delivery,      setDelivery]      = useState(null);
  const [locMsg,        setLocMsg]        = useState('');
  const [locLoad,       setLocLoad]       = useState(false);
  const [placing,       setPlacing]       = useState(false);
  const [error,         setError]         = useState('');
  const [manualKm,      setManualKm]      = useState('');
  const [paymentMethod, setPaymentMethod] = useState('COD');
  const [step,          setStep]          = useState(1); // 1=details 2=location 3=payment

  // Redirect if cart is empty
  useEffect(() => { if (cart.length === 0) navigate('/cart'); }, [cart, navigate]);

  // Pre-fill form from logged-in user
  useEffect(() => {
    if (user) {
      setForm({
        name:    user.name    || '',
        phone:   user.phone   || '',
        address: user.address || ''
      });
    }
  }, [user]);

  const ch = e => setForm(f => ({ ...f, [e.target.name]: e.target.value }));

  /* ── GPS detect ─────────────────────────────────────────── */
  const detectGPS = useCallback(() => {
    setLocLoad(true); setLocMsg(''); setDelivery(null);
    if (!navigator.geolocation) {
      setLocMsg('GPS not supported on this device. Please enter distance manually.');
      setLocLoad(false); return;
    }
    navigator.geolocation.getCurrentPosition(
      async pos => {
        const lat = pos.coords.latitude;
        const lon = pos.coords.longitude;
        setLoc({ lat, lon });
        try {
          const info = await api.checkDelivery(lat, lon, subtotal);
          setDelivery(info);
          setLocMsg('');
          if (info.canDeliver) setStep(3);
        } catch {
          setLocMsg('Could not reach server. Is Spring Boot running on port 8080?');
        }
        setLocLoad(false);
      },
      err => {
        const msgs = {
          1: 'Location access denied. Please allow location or enter distance manually.',
          2: 'Location unavailable. Please enter distance manually.',
          3: 'Location request timed out. Please try again.',
        };
        setLocMsg(msgs[err.code] || 'Location error. Please enter distance manually.');
        setLocLoad(false);
      },
      { timeout: 10000, enableHighAccuracy: false }
    );
  }, [subtotal]);

  /* ── Manual km ─────────────────────────────────────────── */
  const applyManualKm = async () => {
    const km = parseFloat(manualKm);
    if (isNaN(km) || km < 0) { setLocMsg('Enter a valid distance in km'); return; }
    setLocLoad(true);
    try {
      const shop    = await api.getShopLocation();
      const fakeLat = shop.lat + km / 111;
      setLoc({ lat: fakeLat, lon: shop.lon });
      const info = await api.checkDelivery(fakeLat, shop.lon, subtotal);
      setDelivery(info);
      setLocMsg('');
      if (info.canDeliver) setStep(3);
    } catch { setLocMsg('Server not reachable. Make sure backend is running.'); }
    setLocLoad(false);
  };

  /* ── Validate step 1 ─────────────────────────────────── */
  const validateStep1 = () => {
    if (!form.name.trim())    { setError('Please enter your name'); return false; }
    if (!form.phone.trim() || !/^[6-9]\d{9}$/.test(form.phone.trim())) {
      setError('Please enter a valid 10-digit Indian mobile number'); return false;
    }
    if (!form.address.trim()) { setError('Please enter your delivery address'); return false; }
    setError(''); return true;
  };

  /* ══════════════════════════════════════════════════════════
     PLACE ORDER — COD path
  ══════════════════════════════════════════════════════════ */
  const placeOrderCOD = async () => {
    if (!validateStep1()) return;
    if (!loc)                  { setError('Please detect your location first'); return; }
    if (!delivery?.canDeliver) { setError('Sorry, we cannot deliver to your area'); return; }
    if (!delivery?.meetsMinOrder)
      return setError(`Minimum order ₹${delivery.minOrder} required. Add ₹${(delivery.minOrder - subtotal).toFixed(0)} more.`);
    if (!isLoggedIn)           { navigate('/login'); return; }

    setPlacing(true); setError('');
    try {
      const res = await api.placeOrder({
        address:       form.address.trim(),
        customerName:  form.name.trim(),
        customerPhone: form.phone.trim(),
        customerLat:   loc.lat,
        customerLon:   loc.lon,
        paymentMethod: 'COD',
        items: cart.map(i => ({
          productId: Number(i.productId),   // ← ensure it's a number, not string
          quantity:  i.quantity
        }))
      });
      if (res.success) {
        clearCart();
        navigate(`/order/confirmation/${res.orderId}`);
      } else {
        setError(res.error || 'Order failed. Please try again.');
      }
    } catch (e) {
      const msg = e.response?.data?.error || e.message || 'Order failed. Please try again.';
      setError(msg);
    }
    setPlacing(false);
  };

  /* ══════════════════════════════════════════════════════════
     PLACE ORDER — Razorpay path
     Flow: placeOrder (PENDING) → createRazorpayOrder → open dialog → verify → confirm
  ══════════════════════════════════════════════════════════ */
  const placeOrderRazorpay = async () => {
    if (!validateStep1()) return;
    if (!loc)                  { setError('Please detect your location first'); return; }
    if (!delivery?.canDeliver) { setError('Sorry, we cannot deliver to your area'); return; }
    if (!delivery?.meetsMinOrder)
      return setError(`Minimum order ₹${delivery.minOrder} required. Add ₹${(delivery.minOrder - subtotal).toFixed(0)} more.`);
    if (!isLoggedIn)           { navigate('/login'); return; }

    setPlacing(true); setError('');

    try {
      // Step 1: Load Razorpay SDK
      const sdkLoaded = await loadRazorpayScript();
      if (!sdkLoaded) {
        setError('Could not load Razorpay. Check your internet connection.');
        setPlacing(false); return;
      }

      // Step 2: Create shop order first (status = PENDING)
      const orderRes = await api.placeOrder({
        address:       form.address.trim(),
        customerName:  form.name.trim(),
        customerPhone: form.phone.trim(),
        customerLat:   loc.lat,
        customerLon:   loc.lon,
        paymentMethod: 'ONLINE',
        items: cart.map(i => ({
          productId: Number(i.productId),
          quantity:  i.quantity
        }))
      });

      if (!orderRes.success) {
        setError(orderRes.error || 'Could not create order. Please try again.');
        setPlacing(false); return;
      }

      const shopOrderId = orderRes.orderId;

      // Step 3: Create Razorpay order via backend
      const rzpData = await api.createRazorpayOrder(shopOrderId);

      // Step 4: Open Razorpay payment dialog
      const options = {
        key:         rzpData.keyId,
        amount:      rzpData.amount,
        currency:    rzpData.currency,
        name:        'BC Fresh n Fresh',
        description: `Order ${rzpData.orderNumber}`,
        order_id:    rzpData.razorpayOrderId,
        prefill: {
          name:    form.name.trim(),
          contact: form.phone.trim(),
        },
        theme: { color: '#1a8c4e' },
        modal: {
          ondismiss: () => {
            setError('Payment cancelled. Your order is saved — you can pay again from My Orders.');
            setPlacing(false);
          }
        },
        handler: async (response) => {
          // Step 5: Verify signature on backend
          try {
            const verifyRes = await api.verifyPayment({
              razorpayOrderId:   response.razorpay_order_id,
              razorpayPaymentId: response.razorpay_payment_id,
              razorpaySignature: response.razorpay_signature,
              shopOrderId:       String(shopOrderId),
            });
            if (verifyRes.success) {
              clearCart();
              navigate(`/order/confirmation/${shopOrderId}`);
            } else {
              setError('Payment verification failed. Contact support with Payment ID: ' + response.razorpay_payment_id);
            }
          } catch (e) {
            setError('Verification error: ' + (e.response?.data?.error || e.message));
          }
          setPlacing(false);
        }
      };

      const rzp = new window.Razorpay(options);
      rzp.on('payment.failed', (response) => {
        setError(`Payment failed: ${response.error.description}`);
        setPlacing(false);
      });
      rzp.open();

    } catch (e) {
      const msg = e.response?.data?.error || e.message || 'Something went wrong. Please try again.';
      setError(msg);
      setPlacing(false);
    }
  };

  /* ── Trigger correct payment handler ───────────────────── */
  const handlePlaceOrder = () => {
    if (paymentMethod === 'COD') placeOrderCOD();
    else placeOrderRazorpay();
  };

  const deliveryCharge = delivery?.deliveryCharge ?? null;
  const total = deliveryCharge !== null ? subtotal + deliveryCharge : subtotal;

  const canProceed = delivery?.canDeliver && delivery?.meetsMinOrder;

  return (
    <div className="page-wrapper">
      <div className="co-header">
        <h1>Checkout</h1>
        <p>Complete your details and choose payment</p>
      </div>

      {/* Step indicator */}
      <div className="co-steps">
        {[
          { n:1, label:'Your Details'   },
          { n:2, label:'Delivery'       },
          { n:3, label:'Payment'        },
        ].map((s, idx) => (
          <React.Fragment key={s.n}>
            <div className={`co-step ${step >= s.n ? 'active' : ''}`}
              onClick={() => step > s.n && setStep(s.n)}
              style={{ cursor: step > s.n ? 'pointer' : 'default' }}>
              <div className="co-step-num">{step > s.n ? '✓' : s.n}</div>
              {s.label}
            </div>
            {idx < 2 && <div className={`co-step-line ${step > s.n ? 'done' : ''}`} />}
          </React.Fragment>
        ))}
      </div>

      {!isLoggedIn && (
        <div className="alert alert-info" style={{ marginBottom:20 }}>
          💡 <a href="/login" style={{ fontWeight:700, color:'var(--green-dark)' }}>Login</a> or{' '}
          <a href="/register" style={{ fontWeight:700, color:'var(--green-dark)' }}>Register</a> before placing your order
        </div>
      )}

      <div className="co-layout">

        {/* ── LEFT ── */}
        <div className="co-left">

          {/* Step 1 – Your Details */}
          <div className="co-card">
            <div className="co-card-header">
              <div className={`co-card-icon ${step >= 1 ? 'active' : ''}`}>1</div>
              <h2>Your Details</h2>
            </div>
            <div className="co-card-body">
              <div className="form-group">
                <label>Full Name *</label>
                <input name="name" value={form.name} onChange={ch} placeholder="Your full name" />
              </div>
              <div className="form-group">
                <label>Mobile Number *</label>
                <input name="phone" value={form.phone} onChange={ch}
                  placeholder="10-digit mobile" maxLength={10} inputMode="numeric" />
              </div>
              <div className="form-group" style={{ marginBottom:0 }}>
                <label>Delivery Address *</label>
                <textarea name="address" value={form.address} onChange={ch}
                  placeholder="House no, street, area, landmark…" rows={3} style={{ resize:'vertical' }} />
              </div>
              <button className="btn btn-primary btn-sm" style={{ marginTop:12 }}
                onClick={() => { if (validateStep1()) setStep(2); }}>
                Continue to Location →
              </button>
            </div>
          </div>

          {/* Step 2 – Delivery Location */}
          <div className={`co-card ${step < 2 ? 'co-card-disabled' : ''}`}>
            <div className="co-card-header">
              <div className={`co-card-icon ${step >= 2 ? 'active' : ''}`}>2</div>
              <h2>Delivery Location</h2>
            </div>
            {step >= 2 && (
              <div className="co-card-body">
                <p className="co-hint">
                  📦 We deliver within <strong>12 km</strong> from our shop. Share your GPS so we can calculate delivery charges.
                </p>
                <div className="loc-actions">
                  <button className="btn btn-primary" onClick={detectGPS} disabled={locLoad}>
                    {locLoad ? '⏳ Detecting…' : '📡 Detect My GPS Location'}
                  </button>
                </div>
                <div className="manual-row">
                  <label>Or enter distance manually:</label>
                  <input type="number" min="0" max="12" step="0.5"
                    placeholder="e.g. 4.5 km" value={manualKm}
                    onChange={e => setManualKm(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && applyManualKm()} />
                  <button className="btn btn-secondary btn-sm" onClick={applyManualKm}
                    disabled={locLoad}>Calculate</button>
                </div>
                {locMsg && <div className="alert alert-error" style={{ marginTop:14 }}>{locMsg}</div>}
                {delivery && (
                  <div className={`delivery-box ${delivery.canDeliver ? (delivery.meetsMinOrder ? 'can-deliver' : 'min-warn') : 'no-deliver'}`}>
                    <span className="d-icon">
                      {delivery.canDeliver ? (delivery.meetsMinOrder ? '✅' : '⚠️') : '❌'}
                    </span>
                    <div>
                      <strong>{delivery.canDeliver ? delivery.message : 'Outside delivery zone'}</strong>
                      {delivery.canDeliver && (
                        <p>Distance: <strong>{Number(delivery.distanceKm).toFixed(1)} km</strong> · Zone: <strong>{delivery.zone}</strong></p>
                      )}
                      {!delivery.canDeliver && <p>{delivery.message}</p>}
                      {delivery.canDeliver && !delivery.meetsMinOrder && (
                        <p className="min-alert">⚠ Minimum order ₹{delivery.minOrder} needed for this zone</p>
                      )}
                      <span className={`charge-highlight ${deliveryCharge === 0 ? 'free' : ''}`}>
                        {deliveryCharge === 0 ? '🎉 Free Delivery!' : `🚚 Delivery Charge: ₹${deliveryCharge}`}
                      </span>
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>

          {/* Step 3 – Payment */}
          <div className={`co-card ${step < 3 ? 'co-card-disabled' : ''}`}>
            <div className="co-card-header">
              <div className={`co-card-icon ${step >= 3 ? 'active' : ''}`}>3</div>
              <h2>Payment Method</h2>
            </div>
            {step >= 3 && (
              <div className="co-card-body">
                <div className="payment-options">

                  {/* COD option */}
                  <label className={`pay-option ${paymentMethod === 'COD' ? 'selected' : ''}`}>
                    <input type="radio" name="payment" value="COD"
                      checked={paymentMethod === 'COD'}
                      onChange={() => setPaymentMethod('COD')} />
                    <div className="pay-icon">💵</div>
                    <div className="pay-info">
                      <strong>Cash on Delivery</strong>
                      <span>Pay cash when your order arrives</span>
                    </div>
                  </label>

                  {/* Razorpay option */}
                  <label className={`pay-option ${paymentMethod === 'ONLINE' ? 'selected' : ''}`}>
                    <input type="radio" name="payment" value="ONLINE"
                      checked={paymentMethod === 'ONLINE'}
                      onChange={() => setPaymentMethod('ONLINE')} />
                    <div className="pay-icon">💳</div>
                    <div className="pay-info">
                      <strong>Pay Online — UPI / Card / NetBanking</strong>
                      <span>Secure payment via Razorpay · GPay, PhonePe, Paytm, UPI, Cards</span>
                    </div>
                  </label>

                </div>

                {paymentMethod === 'ONLINE' && (
                  <div className="razorpay-info">
                    <div className="rzp-logos">
                      <img src="https://razorpay.com/favicon.ico" alt="" style={{ width:16, height:16 }} />
                      <span style={{ fontWeight:700, color:'#528ff0' }}>Razorpay</span>
                      <span className="rzp-logo-chip">GPay</span>
                      <span className="rzp-logo-chip">PhonePe</span>
                      <span className="rzp-logo-chip">Paytm</span>
                      <span className="rzp-logo-chip">UPI</span>
                      <span className="rzp-logo-chip">Cards</span>
                    </div>
                    <p style={{ fontSize:13, color:'var(--text-mid)', margin:'8px 0 0' }}>
                      🔒 Payments are processed securely by Razorpay. Your card/UPI details are never stored by us.
                      You will be redirected to the payment screen after clicking Place Order.
                    </p>
                  </div>
                )}
              </div>
            )}
          </div>

        </div>

        {/* ── RIGHT: Summary ── */}
        <div className="co-summary">
          <div className="co-summary-header">
            <h2>🧾 Order Summary</h2>
          </div>
          <div className="co-summary-body">
            <div className="sum-items">
              {cart.map(i => (
                <div key={i.productId} className="sum-item">
                  <span className="sum-item-name">{i.productName} × {i.quantity}</span>
                  <span className="sum-item-price">₹{(i.price * i.quantity).toFixed(0)}</span>
                </div>
              ))}
            </div>

            <hr className="sum-divider" />

            <div className="sum-row">
              <span>Subtotal</span>
              <strong>₹{subtotal.toFixed(0)}</strong>
            </div>
            <div className="sum-row">
              <span>Delivery Charge</span>
              {deliveryCharge === null ? (
                <span className="delivery-pending">📍 Detect location</span>
              ) : deliveryCharge === 0 ? (
                <span className="delivery-free">🎉 FREE</span>
              ) : (
                <span className="delivery-amount">₹{deliveryCharge}</span>
              )}
            </div>
            <div className="sum-total-row">
              <span className="sum-total-label">Total</span>
              <span className="sum-total-amount">₹{total.toFixed(0)}</span>
            </div>

            <div className="cod-badge">
              {paymentMethod === 'COD'
                ? '💵 Cash on Delivery'
                : '💳 Pay via Razorpay'}
            </div>

            {error && (
              <div className="alert alert-error" style={{ marginBottom:12 }}>
                ⚠️ {error}
              </div>
            )}

            <button
              className="btn btn-primary btn-lg btn-full place-order-btn"
              onClick={handlePlaceOrder}
              disabled={placing || !canProceed || step < 3}
            >
              {placing
                ? '⏳ Processing…'
                : paymentMethod === 'ONLINE'
                ? '💳 Pay ₹' + total.toFixed(0) + ' via Razorpay'
                : '✅ Place Order — ₹' + total.toFixed(0)}
            </button>

            {!canProceed && step >= 2 && delivery && (
              <p style={{ fontSize:12, color:'#e63946', textAlign:'center', marginTop:8 }}>
                {!delivery.canDeliver ? '❌ Outside delivery zone' : `⚠ Add ₹${(delivery.minOrder - subtotal).toFixed(0)} more to meet minimum order`}
              </p>
            )}
            {step < 3 && (
              <p style={{ fontSize:12, color:'var(--text-light)', textAlign:'center', marginTop:8 }}>
                Complete steps 1 & 2 to place your order
              </p>
            )}

            <p style={{ fontSize:12, color:'var(--text-light)', textAlign:'center', marginTop:10 }}>
              🔒 Secure checkout · Same-day delivery within 12 km
            </p>
          </div>
        </div>

      </div>
    </div>
  );
}
